// Filter replies from target emails in outreach_log
const emails = $input.all();
const replies = emails.filter(item => {
  const from    = item.json.from || '';
  const subject = (item.json.subject || '').toLowerCase();
  const body    = (item.json.text || item.json.snippet || '').toLowerCase();

  // Exclude auto-replies
  const isAutoReply = [
    'out of office', 'auto-reply', 'automatic reply',
    'vacation', 'away from', 'noreply',
  ].some(kw => subject.includes(kw) || body.includes(kw));

  if (isAutoReply) return false;

  // Detect positive reply intent
  const positiveSignals = [
    'interested', 'yes', 'sure', 'please', 'tell me more',
    'call', 'meeting', 'schedule', 'demo', 'price', 'cost',
    'how much', 'magkano', 'tara', 'ok', 'pwede',
  ];
  const hasPositive = positiveSignals.some(kw => body.includes(kw));
  return true; // Return all unread emails, classify in next node
});

console.log(`Emails to process: ${replies.length}`);
return replies.slice(0, 20);

