const email    = $('Filter & Parse Replies').item.json;
const rawReply = $input.item.json.text || $input.item.json.response || '{}';

let classification = {};
try {
  const jsonStart = rawReply.indexOf('{');
  const jsonEnd   = rawReply.lastIndexOf('}') + 1;
  if (jsonStart >= 0) classification = JSON.parse(rawReply.slice(jsonStart, jsonEnd));
} catch(e) {
  classification = { intent: 'other', sentiment: 'neutral', suggested_action: 'no_action' };
}

return [{
  json: {
    email_id:         email.uid || email.id || "unknown",
    from:             email.from,
    subject:          email.subject,
    intent:           classification.intent,
    sentiment:        classification.sentiment,
    suggested_action: classification.suggested_action,
    urgency:          classification.urgency,
    summary:          classification.summary,
    timestamp:        new Date().toISOString(),
  }
}];
